return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 8000;
    var progress = (t % duration) / duration;

    var centerY = H / 2 - 15;
    var radius = 50;
    var centerX1 = W / 2 - 65;
    var centerX2 = W / 2 + 65;

    // Progress breakdown
    // 0 to 1.5s: 0 slices shaded
    // 1.5s to 4s: fill circle 1 (up to 4 slices)
    // 4s to 6.5s: fill 1 slice in circle 2 (total 5 slices)
    // 6.5s to 8s: hold

    var currentShaded = 0;
    if (progress >= 0.15 && progress < 0.40) {
      currentShaded = Math.floor((progress - 0.15) / 0.0625) + 1;
      currentShaded = Math.min(4, currentShaded);
    } else if (progress >= 0.40) {
      currentShaded = 5;
    }

    function drawPie(centerX, startSliceIndex, endSliceIndex, colorShade) {
      var totalSlices = 4;
      for (var i = 0; i < totalSlices; i++) {
        var absoluteSliceIndex = startSliceIndex + i;
        var startAngle = i * (Math.PI * 2 / totalSlices) - Math.PI / 2;
        var endAngle = (i + 1) * (Math.PI * 2 / totalSlices) - Math.PI / 2;

        ctx.beginPath();
        ctx.moveTo(centerX, centerY);
        ctx.arc(centerX, centerY, radius, startAngle, endAngle);
        ctx.closePath();

        if (absoluteSliceIndex < currentShaded) {
          ctx.fillStyle = colorShade;
          ctx.fill();
          ctx.strokeStyle = '#F472B6';
        } else {
          ctx.fillStyle = '#1F2937';
          ctx.fill();
          ctx.strokeStyle = '#374151';
        }
        ctx.lineWidth = 2;
        ctx.stroke();
      }
    }

    // Draw Circle 1 (slices 0 to 3)
    drawPie(centerX1, 0, 3, '#EC4899'); // Pink shade
    // Draw Circle 2 (slices 4 to 7)
    drawPie(centerX2, 4, 7, '#EC4899');

    // Labels under circles
    ctx.fillStyle = '#9CA3AF';
    ctx.font = '11px -apple-system, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('First Whole', centerX1, centerY + radius + 18);
    ctx.fillText('Second Whole', centerX2, centerY + radius + 18);

    // Main Status Text
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillStyle = '#F3F4F6';
    ctx.font = 'bold 20px -apple-system, sans-serif';

    if (currentShaded === 0) {
      ctx.fillText('0 / 4 Shaded', W / 2, H - 35);
    } else if (currentShaded <= 4) {
      ctx.fillText(currentShaded + ' / 4 Shaded', W / 2, H - 35);
    } else {
      ctx.fillText('5 / 4 Shaded', W / 2, H - 35);
      ctx.fillStyle = '#EC4899';
      ctx.font = 'bold 13px -apple-system, sans-serif';
      ctx.fillText('Improper: 5 > 4 (Equals 1 whole and 1/4)', W / 2, H - 15);
    }
  }
};
